import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

# Read the data generated by the C++ program
df = pd.read_csv('results.csv')

# Set up the plotting style
sns.set_theme(style="whitegrid")
fig, axes = plt.subplots(1, 2, figsize=(15, 6))

# Plot 1: Performance (TFLOPS) - HIGHER IS BETTER
sns.barplot(
    data=df, x='Size', y='TFLOPS', hue='Precision', 
    palette=['#e74c3c', '#3498db', '#2ecc71'], ax=axes[0]
)
axes[0].set_title('Computational Performance (TFLOPS)\nHigher is Better', fontsize=14, fontweight='bold')
axes[0].set_ylabel('TeraFLOPS (Trillions of operations/sec)')
axes[0].set_xlabel('Matrix Size (N x N)')

# Plot 2: Execution Time - LOWER IS BETTER
# Using a logarithmic scale for the Y-axis because the time difference is huge
sns.barplot(
    data=df, x='Size', y='Time_ms', hue='Precision', 
    palette=['#e74c3c', '#3498db', '#2ecc71'], ax=axes[1]
)
axes[1].set_title('Execution Time per Matrix Multiplication\nLower is Better (Log Scale)', fontsize=14, fontweight='bold')
axes[1].set_ylabel('Time (milliseconds)')
axes[1].set_xlabel('Matrix Size (N x N)')
axes[1].set_yscale("log") # Log scale makes the massive gap easier to see

plt.tight_layout()
plt.show()